import java.time.LocalDate
import java.time.format.DateTimeFormatter
import java.time.format.FormatStyle
import java.time.temporal.ChronoUnit

private val DATE_FORMAT = DateTimeFormatter.ofLocalizedDate(FormatStyle.MEDIUM)

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun CruiseDetailScreen(
    cruiseId: Long,
    onNavigateUp: () -> Unit,
    onEditCruise: () -> Unit,
    viewModel: CruiseDetailViewModel = hiltViewModel(),
) {
    LaunchedEffect(cruiseId) {
        viewModel.loadCruise(cruiseId)
    }

    val uiState by viewModel.uiState.collectAsStateWithLifecycle()
    val snackbarHostState = remember { SnackbarHostState() }
    var editingPort by remember { mutableStateOf<PortOfCall?>(null) }
    var addingPortOnDate by remember { mutableStateOf<LocalDate?>(null) }
    var addingSeaDayOnDate by remember { mutableStateOf<LocalDate?>(null) }
    // Track which port localId is expanded (null = none)
    var expandedPortLocalId by remember { mutableStateOf<String?>(null) }

    LaunchedEffect(uiState.fetchMessage) {
        uiState.fetchMessage?.let { msg ->
            snackbarHostState.showSnackbar(msg)
            viewModel.clearMessage()
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = {
                    Column {
                        Text(uiState.cruiseWithPorts?.cruise?.name ?: "")
                        uiState.cruiseWithPorts?.cruise?.let { cruise ->
                            Text(
                                text = "${DATE_FORMAT.format(cruise.sailDate)} – ${DATE_FORMAT.format(cruise.returnDate)}",
                                style = MaterialTheme.typography.bodySmall,
                            )
                        }
                    }
                },
                navigationIcon = {
                    IconButton(onClick = onNavigateUp) {
                        Icon(
                            imageVector = Icons.AutoMirrored.Filled.ArrowBack,
                            contentDescription = "Navigate up",
                        )
                    }
                },
            )
        },
        snackbarHost = { SnackbarHost(snackbarHostState) },
    ) { padding ->
        val scrollState = rememberScrollState()
        Column(
            modifier = Modifier
                .padding(padding)
                .fillMaxSize()
                .verticalScroll(scrollState),
        ) {
            // Action buttons
            Row(modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp)) {
                OutlinedButton(onClick = onEditCruise) { Text("Edit") }
                Spacer(modifier = Modifier.weight(1f))
                Button(
                    onClick = { viewModel.fetchWeather(forceRefresh = true) },
                    enabled = !uiState.isFetchingWeather,
                ) {
                    Text("Refresh Weather")
                }
            }

            // Cruise metadata
            val cruiseWithPorts = uiState.cruiseWithPorts
            if (cruiseWithPorts != null) {
                val cruise = cruiseWithPorts.cruise
                val cruiseLineDisplay = CruiseLine.entries.find { it.name == cruise.cruiseLine }?.displayName
                val metaParts = listOfNotNull(
                    cruiseLineDisplay,
                    cruise.shipName.takeIf { it.isNotBlank() },
                )
                if (metaParts.isNotEmpty()) {
                    Text(
                        text = metaParts.joinToString("  \u2022  "),
                        style = MaterialTheme.typography.bodyMedium,
                        modifier = Modifier.padding(horizontal = 16.dp, vertical = 4.dp),
                    )
                }

                // Day-by-day itinerary
                val portsByDate = cruiseWithPorts.allPortsChronological
                    .groupBy { it.date }
                val totalDays = ChronoUnit.DAYS.between(cruise.sailDate, cruise.returnDate).toInt() + 1
                for (dayIndex in 0 until totalDays) {
                    val date = cruise.sailDate.plusDays(dayIndex.toLong())
                    val dayNumber = dayIndex + 1
                    val portsOnDay = portsByDate[date]
                    // Separate sea days from actual ports
                    val seaDays = portsOnDay?.filter { it.type == PortType.SEA_DAY }
                    val realPorts = portsOnDay?.filter { it.type != PortType.SEA_DAY }

                    if (!realPorts.isNullOrEmpty()) {
                        // Day has real ports — show weather cards
                        realPorts.forEach { port ->
                            val isExpanded = expandedPortLocalId == port.localId
                            WeatherCard(
                                port = port,
                                summary = uiState.portWeather[port.id],
                                dayNumber = dayNumber,
                                isExpanded = isExpanded,
                                onEdit = { editingPort = port },
                                scrollState = scrollState,
                                modifier = Modifier.clickable {
                                    expandedPortLocalId = if (isExpanded) null else port.localId
                                },
                            )
                        }
                    } else {
                        // Sea day (with or without saved SEA_DAY entity)
                        val seaDayEntity = seaDays?.firstOrNull()
                        SeaDayRow(
                            dayNumber = dayNumber,
                            date = date,
                            notes = seaDayEntity?.notes?.takeIf { it.isNotBlank() },
                            onAddPort = { addingPortOnDate = date },
                            onAddNote = {
                                if (seaDayEntity != null) {
                                    editingPort = seaDayEntity
                                } else {
                                    addingSeaDayOnDate = date
                                }
                            },
                        )
                    }
                }

                Spacer(modifier = Modifier.height(8.dp))

                Text(
                    text = "* Based on historical 5-year averages (±2 day window)",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant,
                    modifier = Modifier.padding(horizontal = 16.dp),
                )
            }
        }

        if (uiState.isFetchingWeather) {
            LoadingOverlay(message = "Fetching weather data…")
        }
    }

    // Edit any port type
    editingPort?.let { port ->
        val cruise = uiState.cruiseWithPorts?.cruise ?: return@let
        PortOfCallSheet(
            cruiseId = cruise.id,
            sailDate = cruise.sailDate,
            returnDate = cruise.returnDate,
            existingPort = port,
            portType = port.type,
            onSave = { updated -> viewModel.updatePortOfCall(updated) },
            onDelete = if (port.type == PortType.PORT_OF_CALL || port.type == PortType.SEA_DAY) {
                { deleted -> viewModel.deletePortOfCall(deleted.id) }
            } else null,
            onDismiss = { editingPort = null },
            onGeocode = { query -> viewModel.geocodeQuery(query) },
        )
    }

    // Add port of call
    addingPortOnDate?.let { targetDate ->
        val cruise = uiState.cruiseWithPorts?.cruise ?: return@let
        PortOfCallSheet(
            cruiseId = cruise.id,
            sailDate = cruise.sailDate,
            returnDate = cruise.returnDate,
            lastPortDate = targetDate.minusDays(1),
            onSave = { port -> viewModel.addPortOfCall(port) },
            onDismiss = { addingPortOnDate = null },
            onGeocode = { query -> viewModel.geocodeQuery(query) },
        )
    }

    // Add sea day note
    addingSeaDayOnDate?.let { targetDate ->
        val cruise = uiState.cruiseWithPorts?.cruise ?: return@let
        PortOfCallSheet(
            cruiseId = cruise.id,
            sailDate = cruise.sailDate,
            returnDate = cruise.returnDate,
            lastPortDate = targetDate.minusDays(1),
            portType = PortType.SEA_DAY,
            onSave = { port -> viewModel.addPortOfCall(port.copy(date = targetDate)) },
            onDismiss = { addingSeaDayOnDate = null },
            onGeocode = { query -> viewModel.geocodeQuery(query) },
        )
    }
}

@Composable
private fun SeaDayRow(
    dayNumber: Int,
    date: LocalDate,
    notes: String? = null,
    onAddPort: () -> Unit,
    onAddNote: () -> Unit,
) {
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 24.dp, vertical = 2.dp),
    ) {
        Row(verticalAlignment = Alignment.CenterVertically) {
            Text(
                text = "Day $dayNumber  •  ${DATE_FORMAT.format(date)}  •  At Sea",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
                modifier = Modifier.weight(1f),
            )
            TextButton(onClick = onAddNote) {
                Text("Note", style = MaterialTheme.typography.labelSmall)
            }
            TextButton(onClick = onAddPort) {
                Icon(
                    imageVector = Icons.Default.Add,
                    contentDescription = "Add port on day $dayNumber",
                    modifier = Modifier.padding(end = 4.dp),
                )
                Text("Port", style = MaterialTheme.typography.labelSmall)
            }
        }
        if (notes != null) {
            Text(
                text = notes,
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
                modifier = Modifier.padding(start = 8.dp, bottom = 4.dp),
            )
        }
    }
}
